  "dashboard.mejores_clientes_desc": { es: "Los que más te han comprado, por total histórico.", en: "The ones who've bought the most from you, by historical total.", pt: "Os que mais compraram de você, pelo total histórico.", fr: "Ceux qui vous ont le plus acheté, par total historique.", de: "Diejenigen, die am meisten bei dir gekauft haben, nach Gesamtsumme.", zh: "历史累计购买最多的客户。", it: "Quelli che hanno acquistato di più da te, per totale storico." },
  "dashboard.cliente_eliminado": { es: "Cliente eliminado", en: "Deleted customer", pt: "Cliente excluído", fr: "Client supprimé", de: "Gelöschter Kunde", zh: "已删除的客户", it: "Cliente eliminato" },
  "dashboard.articulos_criticos": { es: "Artículos por debajo de su stock mínimo", en: "Items below their minimum stock", pt: "Itens abaixo do estoque mínimo", fr: "Articles sous leur stock minimum", de: "Artikel unter ihrem Mindestbestand", zh: "低于最低库存的商品", it: "Articoli sotto la scorta minima" },
  "dashboard.sin_inventario_bajo": { es: "No tienes productos con inventario bajo.", en: "You have no low-stock products.", pt: "Você não tem produtos com estoque baixo.", fr: "Vous n'avez aucun produit en stock bas.", de: "Du hast keine Produkte mit niedrigem Bestand.", zh: "没有低库存商品。", it: "Non hai prodotti con scorte basse." },
  "dashboard.stock_actual": { es: "Stock actual", en: "Current stock", pt: "Estoque atual", fr: "Stock actuel", de: "Aktueller Bestand", zh: "当前库存", it: "Scorta attuale" },
