  "asistente.agotados_extra": { es: "...y {n} más.", en: "...and {n} more.", pt: "...e mais {n}.", fr: "...et {n} de plus.", de: "...und {n} weitere.", zh: "……还有{n}个。", it: "...e altri {n}." },
  "asistente.inv_vacio": { es: "Todavía no tienes productos registrados en tu catálogo.", en: "You don't have any products registered in your catalog yet.", pt: "Você ainda não tem produtos registrados em seu catálogo.", fr: "Vous n'avez pas encore de produits enregistrés dans votre catalogue.", de: "Du hast noch keine Produkte in deinem Katalog erfasst.", zh: "您的目录中还没有登记任何产品。", it: "Non hai ancora prodotti registrati nel tuo catalogo." },
  "asistente.inv_resumen": { es: "Tu catálogo tiene **{n} productos**, con **{unidades} unidades** en total.", en: "Your catalog has **{n} products**, with **{unidades} units** in total.", pt: "Seu catálogo tem **{n} produtos**, com **{unidades} unidades** no total.", fr: "Votre catalogue compte **{n} produits**, avec **{unidades} unités** au total.", de: "Dein Katalog hat **{n} Produkte** mit insgesamt **{unidades} Einheiten**.", zh: "您的目录共有**{n}个产品**，总计**{unidades}件**库存。", it: "Il tuo catalogo ha **{n} prodotti**, con **{unidades} unità** in totale." },
