  // Usuarios y permisos
  "usuarios.aviso": { es: "Cada miembro que agregues aquí entra con tu correo, su propio nombre y su propia contraseña — nunca necesita la contraseña de la cuenta principal. Queda limitado a los permisos que le diste. Configúrale una contraseña abajo: sin ella, no podrá entrar.", en: "Anyone you add here signs in with your email, their own name, and their own password — they never need the main account's password. They're limited to the permissions you gave them. Set a password for them below: without one, they won't be able to sign in.", pt: "Qualquer pessoa que você adicionar aqui entra com seu e-mail, o próprio nome e a própria senha — nunca precisa da senha da conta principal. Fica limitada às permissões que você deu. Configure uma senha abaixo: sem ela, não conseguirá entrar.", fr: "Toute personne que vous ajoutez ici se connecte avec votre e-mail, son propre nom et son propre mot de passe — elle n'a jamais besoin du mot de passe du compte principal. Elle est limitée aux permissions que vous lui avez données. Configurez-lui un mot de passe ci-dessous : sans cela, elle ne pourra pas se connecter.", de: "Jede Person, die du hier hinzufügst, meldet sich mit deiner E-Mail, ihrem eigenen Namen und ihrem eigenen Passwort an — sie braucht nie das Passwort des Hauptkontos. Sie ist auf die Rechte beschränkt, die du ihr gegeben hast. Lege unten ein Passwort für sie fest: ohne eines kann sie sich nicht anmelden.", zh: "您在这里添加的任何人都使用您的邮箱、自己的姓名和自己的密码登录 — 完全不需要主账户的密码。他们会被限制在您赋予的权限范围内。请在下方为其设置密码：没有密码将无法登录。", it: "Chiunque tu aggiunga qui accede con la tua email, il proprio nome e la propria password — non ha mai bisogno della password dell'account principale. Resta limitato ai permessi che gli hai assegnato. Configura una password qui sotto: senza di essa, non potrà accedere." },
  "usuarios.cambiar_contrasena": { es: "Cambiar mi contraseña", en: "Change my password", pt: "Alterar minha senha", fr: "Changer mon mot de passe", de: "Mein Passwort ändern", zh: "修改我的密码", it: "Cambia la mia password" },
  "usuarios.cambiar_contrasena_desc": { es: "Esto cambia la contraseña de tu propia cuenta.", en: "This changes your own account's password.", pt: "Isso altera a senha da sua própria conta.", fr: "Cela change le mot de passe de votre propre compte.", de: "Dies ändert das Passwort deines eigenen Kontos.", zh: "这将更改您自己账户的密码。", it: "Questo cambia la password del tuo account personale." },
  "usuarios.cambiar_contrasena_miembro_desc": { es: "Como miembro del equipo no tienes una contraseña propia de cuenta — pídele al dueño de la cuenta que cambie tu contraseña de acceso desde \"Editar miembro\".", en: "As a team member you don't have your own account password — ask the account owner to change your access password from \"Edit member\".", pt: "Como membro da equipe, você não tem uma senha de conta própria — peça ao dono da conta para alterar sua senha de acesso em \"Editar membro\".", fr: "En tant que membre de l'équipe, vous n'avez pas de mot de passe de compte propre — demandez au propriétaire du compte de changer votre mot de passe d'accès depuis « Modifier le membre ».", de: "Als Teammitglied hast du kein eigenes Kontopasswort — bitte den Kontoinhaber, dein Zugangspasswort über \"Mitglied bearbeiten\" zu ändern.", zh: "作为团队成员，您没有自己的账户密码——请账户所有者通过“编辑成员”更改您的访问密码。", it: "Come membro del team non hai una password personale dell'account — chiedi al titolare dell'account di cambiare la tua password di accesso da \"Modifica membro\"." },
  "usuarios.nueva_contrasena": { es: "Nueva contraseña", en: "New password", pt: "Nova senha", fr: "Nouveau mot de passe", de: "Neues Passwort", zh: "新密码", it: "Nuova password" },
  "usuarios.confirmar_contrasena": { es: "Confirmar contraseña", en: "Confirm password", pt: "Confirmar senha", fr: "Confirmer le mot de passe", de: "Passwort bestätigen", zh: "确认密码", it: "Conferma password" },
  "usuarios.actualizar_contrasena": { es: "Actualizar contraseña", en: "Update password", pt: "Atualizar senha", fr: "Mettre à jour le mot de passe", de: "Passwort aktualisieren", zh: "更新密码", it: "Aggiorna password" },
