  "usuarios.equipo_desc": { es: "Roles y permisos de las personas que trabajan contigo.", en: "Roles and permissions of the people working with you.", pt: "Funções e permissões das pessoas que trabalham com você.", fr: "Rôles et permissions des personnes qui travaillent avec vous.", de: "Rollen und Rechte der Personen, die mit dir arbeiten.", zh: "与您共事的人员的角色和权限。", it: "Ruoli e permessi delle persone che lavorano con te." },
