  "analisis.margen_promedio": { es: "Margen promedio", en: "Average margin", pt: "Margem média", fr: "Marge moyenne", de: "Durchschnittliche Marge", zh: "平均利润率", it: "Margine medio" },
  "analisis.frecuencia_compra": { es: "Frecuencia de compra", en: "Purchase frequency", pt: "Frequência de compra", fr: "Fréquence d'achat", de: "Kaufhäufigkeit", zh: "购买频率", it: "Frequenza di acquisto" },
  "analisis.frecuencia_alta": { es: "Alta — se compra seguido", en: "High — bought often", pt: "Alta — comprado com frequência", fr: "Élevée — acheté souvent", de: "Hoch — wird häufig gekauft", zh: "高——经常购买", it: "Alta — si acquista spesso" },
  "analisis.frecuencia_media": { es: "Media", en: "Medium", pt: "Média", fr: "Moyenne", de: "Mittel", zh: "中等", it: "Media" },
