  "analisis.ganancia_estimada_mes": { es: "Ganancia estimada al mes", en: "Estimated monthly profit", pt: "Lucro estimado por mês", fr: "Bénéfice mensuel estimé", de: "Geschätzter monatlicher Gewinn", zh: "预计月利润", it: "Guadagno stimato al mese" },
