  "analisis.precio_referencia": { es: "Precio de referencia en esta categoría", en: "Reference price in this category", pt: "Preço de referência nessa categoria", fr: "Prix de référence dans cette catégorie", de: "Referenzpreis in dieser Kategorie", zh: "该分类的参考价格", it: "Prezzo di riferimento in questa categoria" },
  "analisis.disclaimer": { es: "Estimado a partir del promedio de tus propios productos y ventas de esta categoría — no de datos de mercado externos. Úsalo como referencia, no como garantía.", en: "Estimated from the average of your own products and sales in this category — not external market data. Use it as a reference, not a guarantee.", pt: "Estimado a partir da média dos seus próprios produtos e vendas nessa categoria — não de dados de mercado externos. Use como referência, não como garantia.", fr: "Estimé à partir de la moyenne de vos propres produits et ventes dans cette catégorie — pas de données de marché externes. À utiliser comme référence, pas comme garantie.", de: "Geschätzt anhand des Durchschnitts deiner eigenen Produkte und Verkäufe in dieser Kategorie — nicht anhand externer Marktdaten. Nutze es als Orientierung, nicht als Garantie.", zh: "根据你自己在该分类下的产品和销售平均值估算——并非外部市场数据。请作为参考，而非保证。", it: "Stimato in base alla media dei tuoi prodotti e vendite in questa categoria — non da dati di mercato esterni. Usalo come riferimento, non come garanzia." },
  "analisis.agregar_al_inventario": { es: "Agregar este producto al inventario", en: "Add this product to inventory", pt: "Adicionar este produto ao inventário", fr: "Ajouter ce produit à l'inventaire", de: "Dieses Produkt zum Inventar hinzufügen", zh: "将此产品添加到库存", it: "Aggiungi questo prodotto all'inventario" },

