  "comun.msg_stock_cambio": { es: "El stock cambió mientras se procesaba. Intenta de nuevo.", en: "Stock changed while this was processing. Try again.", pt: "O estoque mudou enquanto isso era processado. Tente novamente.", fr: "Le stock a changé pendant le traitement. Réessayez.", de: "Der Bestand hat sich während der Verarbeitung geändert. Versuche es erneut.", zh: "处理过程中库存发生了变化，请重试。", it: "La scorta è cambiata durante l'elaborazione. Riprova." },
  "permisos.sin_acceso": { es: "No tienes permiso para ver esta sección. Pídele acceso a quien administra la cuenta.", en: "You don't have permission to view this section. Ask whoever manages the account for access.", pt: "Você não tem permissão para ver esta seção. Peça acesso a quem administra a conta.", fr: "Vous n'avez pas la permission de voir cette section. Demandez l'accès à la personne qui gère le compte.", de: "Du hast keine Berechtigung, diesen Bereich zu sehen. Bitte den Kontoverwalter um Zugriff.", zh: "您没有权限查看此部分。请向账户管理者申请访问权限。", it: "Non hai il permesso di vedere questa sezione. Chiedi l'accesso a chi amministra l'account." },
  "permisos.sin_acceso_accion": { es: "No tienes permiso para hacer esto. Pídele acceso a quien administra la cuenta.", en: "You don't have permission to do this. Ask whoever manages the account for access.", pt: "Você não tem permissão para fazer isso. Peça acesso a quem administra a conta.", fr: "Vous n'avez pas la permission de faire cela. Demandez l'accès à la personne qui gère le compte.", de: "Du hast keine Berechtigung, das zu tun. Bitte den Kontoverwalter um Zugriff.", zh: "您没有权限执行此操作。请向账户管理者申请访问权限。", it: "Non hai il permesso di fare questo. Chiedi l'accesso a chi amministra l'account." },
  "clientes.token_pendiente": { es: "Todavía no tienes el enlace del portal. Ejecuta la migración de Portal de Clientes en Supabase.", en: "The portal link isn't ready yet. Run the Customer Portal migration in Supabase.", pt: "O link do portal ainda não está pronto. Execute a migração do Portal de Clientes no Supabase.", fr: "Le lien du portail n'est pas encore prêt. Exécutez la migration du Portail Client dans Supabase.", de: "Der Portal-Link ist noch nicht bereit. Führe die Portal-Migration in Supabase aus.", zh: "门户链接尚未就绪，请在 Supabase 中执行客户门户的迁移脚本。", it: "Non hai ancora il link del portale. Esegui la migrazione del Portale Clienti in Supabase." },
  "comun.msg_error_cargar_datos": { es: "No se pudieron cargar los datos. Revisa tu conexión a Internet; si sigues conectado, puede que falte ejecutar el script SQL de este módulo en Supabase.", en: "Couldn't load the data. Check your Internet connection; if you're still connected, this module's SQL script may not have been run in Supabase yet.", pt: "Não foi possível carregar os dados. Verifique sua conexão com a Internet; se ainda estiver conectado, talvez falte executar o script SQL deste módulo no Supabase.", fr: "Impossible de charger les données. Vérifiez votre connexion Internet ; si vous êtes toujours connecté, il se peut que le script SQL de ce module n'ait pas encore été exécuté dans Supabase.", de: "Daten konnten nicht geladen werden. Überprüfe deine Internetverbindung; falls du weiterhin verbunden bist, wurde das SQL-Skript dieses Moduls in Supabase eventuell noch nicht ausgeführt.", zh: "数据加载失败。请检查您的网络连接；如果仍然联网，可能是此模块的 SQL 脚本尚未在 Supabase 中执行。", it: "Non è stato possibile caricare i dati. Controlla la tua connessione a Internet; se sei ancora connesso, potrebbe mancare l'esecuzione dello script SQL di questo modulo in Supabase." },
