  // Catálogo en Línea (gestión, autenticado)
  "catalogo_linea.subtitulo": { es: "Comparte un catálogo público de tus productos con tus clientes.", en: "Share a public catalog of your products with your customers.", pt: "Compartilhe um catálogo público dos seus produtos com seus clientes.", fr: "Partagez un catalogue public de vos produits avec vos clients.", de: "Teile einen öffentlichen Katalog deiner Produkte mit deinen Kunden.", zh: "与客户分享您的产品公开目录。", it: "Condividi un catalogo pubblico dei tuoi prodotti con i tuoi clienti." },
  "catalogo_linea.activar": { es: "Activar catálogo", en: "Activate catalog", pt: "Ativar catálogo", fr: "Activer le catalogue", de: "Katalog aktivieren", zh: "启用目录", it: "Attiva catalogo" },
  "catalogo_linea.desactivar": { es: "Desactivar catálogo", en: "Deactivate catalog", pt: "Desativar catálogo", fr: "Désactiver le catalogue", de: "Katalog deaktivieren", zh: "停用目录", it: "Disattiva catalogo" },
  "catalogo_linea.activar_desc": { es: "Cuando está activo, cualquiera con el enlace puede ver tu nombre, logo y tus productos activos (sin precios de costo ni datos internos).", en: "When active, anyone with the link can see your name, logo and active products (no cost prices or internal data).", pt: "Quando ativo, qualquer pessoa com o link pode ver seu nome, logo e produtos ativos (sem preços de custo nem dados internos).", fr: "Lorsqu'il est actif, toute personne disposant du lien peut voir votre nom, logo et produits actifs (sans prix de revient ni données internes).", de: "Wenn aktiv, kann jeder mit dem Link deinen Namen, dein Logo und deine aktiven Produkte sehen (keine Kostenpreise oder internen Daten).", zh: "启用后，任何持有链接的人都可以看到您的名称、标志和已上架产品（不含成本价或内部数据）。", it: "Quando è attivo, chiunque abbia il link può vedere il tuo nome, logo e i tuoi prodotti attivi (senza prezzi di costo né dati interni)." },
  "catalogo_linea.msg_falta_empresa": { es: "Primero guarda los datos de tu negocio en Configuración → Empresa.", en: "First save your business info in Settings → Company.", pt: "Primeiro salve os dados da sua empresa em Configurações → Empresa.", fr: "Enregistrez d'abord les informations de votre entreprise dans Paramètres → Entreprise.", de: "Speichere zuerst deine Unternehmensdaten unter Einstellungen → Unternehmen.", zh: "请先在「设置 → 公司」中保存您的企业信息。", it: "Prima salva i dati della tua azienda in Impostazioni → Azienda." },
  "catalogo_linea.msg_error_guardar": { es: "No se pudo actualizar el catálogo.", en: "Could not update the catalog.", pt: "Não foi possível atualizar o catálogo.", fr: "Impossible de mettre à jour le catalogue.", de: "Katalog konnte nicht aktualisiert werden.", zh: "目录更新失败。", it: "Impossibile aggiornare il catalogo." },
  "catalogo_linea.copiar_enlace": { es: "Copiar enlace", en: "Copy link", pt: "Copiar link", fr: "Copier le lien", de: "Link kopieren", zh: "复制链接", it: "Copia link" },
  "catalogo_linea.copiado": { es: "¡Copiado!", en: "Copied!", pt: "Copiado!", fr: "Copié !", de: "Kopiert!", zh: "已复制！", it: "Copiato!" },
  "catalogo_linea.ver_catalogo": { es: "Ver catálogo", en: "View catalog", pt: "Ver catálogo", fr: "Voir le catalogue", de: "Katalog ansehen", zh: "查看目录", it: "Vedi catalogo" },
  "catalogo_linea.vista_previa": { es: "Vista previa", en: "Preview", pt: "Pré-visualização", fr: "Aperçu", de: "Vorschau", zh: "预览", it: "Anteprima" },
  "catalogo_linea.sin_productos": { es: "No tienes productos activos todavía.", en: "You don't have any active products yet.", pt: "Você ainda não tem produtos ativos.", fr: "Vous n'avez pas encore de produits actifs.", de: "Du hast noch keine aktiven Produkte.", zh: "您还没有已上架的产品。", it: "Non hai ancora prodotti attivi." },

