  "catalogo_publico.subtitulo": { es: "Catálogo de productos", en: "Product catalog", pt: "Catálogo de produtos", fr: "Catalogue de produits", de: "Produktkatalog", zh: "产品目录", it: "Catalogo prodotti" },
  "catalogo_publico.no_disponible": { es: "Este catálogo no está disponible", en: "This catalog isn't available", pt: "Este catálogo não está disponível", fr: "Ce catalogue n'est pas disponible", de: "Dieser Katalog ist nicht verfügbar", zh: "该目录暂不可用", it: "Questo catalogo non è disponibile" },
  "catalogo_publico.no_disponible_desc": { es: "El enlace es incorrecto o el negocio todavía no activó su catálogo.", en: "The link is incorrect or the business hasn't activated its catalog yet.", pt: "O link está incorreto ou o negócio ainda não ativou seu catálogo.", fr: "Le lien est incorrect ou l'entreprise n'a pas encore activé son catalogue.", de: "Der Link ist falsch oder das Unternehmen hat seinen Katalog noch nicht aktiviert.", zh: "链接有误，或该商家尚未启用其目录。", it: "Il link non è corretto o l'azienda non ha ancora attivato il suo catalogo." },
