  "login.placeholder_usuario": { es: "Tu nombre, si el dueño te agregó al equipo", en: "Your name, if the owner added you to the team", pt: "Seu nome, se o proprietário te adicionou à equipe", fr: "Votre nom, si le propriétaire vous a ajouté à l'équipe", de: "Dein Name, falls der Kontoinhaber dich zum Team hinzugefügt hat", zh: "如果账户所有者已将您加入团队，请输入您的姓名", it: "Il tuo nome, se il titolare ti ha aggiunto al team" },
