  "login.btn_registrarse": { es: "Registrarse", en: "Sign up", pt: "Registrar-se", fr: "S'inscrire", de: "Registrieren", zh: "注册", it: "Registrati" },
  "login.btn_ir_registro": { es: "¿No tienes cuenta? Regístrate", en: "Don't have an account? Sign up", pt: "Não tem uma conta? Cadastre-se", fr: "Vous n'avez pas de compte ? Inscrivez-vous", de: "Kein Konto? Registrieren", zh: "没有账户？立即注册", it: "Non hai un account? Registrati" },
  "login.btn_ir_login": { es: "¿Ya tienes cuenta? Inicia sesión", en: "Already have an account? Sign in", pt: "Já tem uma conta? Entre", fr: "Vous avez déjà un compte ? Connectez-vous", de: "Bereits ein Konto? Anmelden", zh: "已有账户？立即登录", it: "Hai già un account? Accedi" },
