  "login.titulo_recuperar": { es: "Recupera tu contraseña", en: "Reset your password", pt: "Recupere sua senha", fr: "Récupérez votre mot de passe", de: "Passwort zurücksetzen", zh: "重置密码", it: "Recupera la tua password" },
  "login.subtitulo_recuperar": { es: "Te enviaremos un enlace por correo para elegir una contraseña nueva", en: "We'll email you a link to choose a new password", pt: "Enviaremos um link por e-mail para você escolher uma nova senha", fr: "Nous vous enverrons un lien par e-mail pour choisir un nouveau mot de passe", de: "Wir senden dir einen Link per E-Mail, um ein neues Passwort festzulegen", zh: "我们会向您发送一封邮件，附带用于设置新密码的链接", it: "Ti invieremo un link via email per scegliere una nuova password" },
  "login.btn_enviar_recuperacion": { es: "Enviar enlace de recuperación", en: "Send reset link", pt: "Enviar link de recuperação", fr: "Envoyer le lien de récupération", de: "Zurücksetzungslink senden", zh: "发送重置链接", it: "Invia link di recupero" },
  "login.msg_recuperacion_enviada": { es: "Si ese correo tiene una cuenta, te llegará un enlace para elegir una contraseña nueva.", en: "If that email has an account, you'll receive a link to choose a new password.", pt: "Se esse e-mail tiver uma conta, você receberá um link para escolher uma nova senha.", fr: "Si cet e-mail est associé à un compte, vous recevrez un lien pour choisir un nouveau mot de passe.", de: "Falls zu dieser E-Mail ein Konto gehört, erhältst du einen Link, um ein neues Passwort festzulegen.", zh: "如果该邮箱已注册账户，您将收到一封邮件，其中包含用于设置新密码的链接。", it: "Se quell'email ha un account, riceverai un link per scegliere una nuova password." },

