  "restablecer.titulo": { es: "Restablece tu contraseña", en: "Reset your password", pt: "Redefina sua senha", fr: "Réinitialisez votre mot de passe", de: "Setze dein Passwort zurück", zh: "重置密码", it: "Reimposta la tua password" },
  "restablecer.subtitulo": { es: "Elige una contraseña nueva para tu cuenta", en: "Choose a new password for your account", pt: "Escolha uma nova senha para sua conta", fr: "Choisissez un nouveau mot de passe pour votre compte", de: "Wähle ein neues Passwort für dein Konto", zh: "为您的账户选择一个新密码", it: "Scegli una nuova password per il tuo account" },
  "restablecer.msg_enlace_invalido": { es: "Este enlace ya venció o ya fue usado. Pide uno nuevo desde la pantalla de inicio de sesión.", en: "This link has expired or was already used. Request a new one from the login screen.", pt: "Este link já venceu ou já foi usado. Peça um novo na tela de login.", fr: "Ce lien a expiré ou a déjà été utilisé. Demandez-en un nouveau depuis l'écran de connexion.", de: "Dieser Link ist abgelaufen oder wurde bereits verwendet. Fordere einen neuen auf dem Anmeldebildschirm an.", zh: "此链接已过期或已被使用。请在登录页面重新申请一个。", it: "Questo link è scaduto o è già stato usato. Richiedine uno nuovo dalla schermata di accesso." },
  "restablecer.msg_exito": { es: "Tu contraseña se actualizó correctamente.", en: "Your password was updated successfully.", pt: "Sua senha foi atualizada com sucesso.", fr: "Votre mot de passe a été mis à jour avec succès.", de: "Dein Passwort wurde erfolgreich aktualisiert.", zh: "您的密码已成功更新。", it: "La tua password è stata aggiornata correttamente." },
  "restablecer.btn_ir_app": { es: "Ir a CoreStock", en: "Go to CoreStock", pt: "Ir para o CoreStock", fr: "Aller à CoreStock", de: "Zu CoreStock", zh: "前往 CoreStock", it: "Vai a CoreStock" },
  "restablecer.btn_guardar": { es: "Guardar contraseña", en: "Save password", pt: "Salvar senha", fr: "Enregistrer le mot de passe", de: "Passwort speichern", zh: "保存密码", it: "Salva password" },
  "restablecer.msg_error": { es: "No se pudo actualizar tu contraseña. Intenta de nuevo o pide un nuevo enlace.", en: "We couldn't update your password. Try again or request a new link.", pt: "Não foi possível atualizar sua senha. Tente novamente ou peça um novo link.", fr: "Impossible de mettre à jour votre mot de passe. Réessayez ou demandez un nouveau lien.", de: "Dein Passwort konnte nicht aktualisiert werden. Versuche es erneut oder fordere einen neuen Link an.", zh: "无法更新您的密码。请重试或申请新链接。", it: "Impossibile aggiornare la tua password. Riprova o richiedi un nuovo link." },

