  "ventas_rapidas.sin_productos_catalogo": { es: "Todavía no tienes productos en tu inventario", en: "You don't have any products in your inventory yet", pt: "Você ainda não tem produtos no seu estoque", fr: "Vous n'avez pas encore de produits dans votre inventaire", de: "Du hast noch keine Produkte in deinem Inventar", zh: "您的库存中还没有任何产品", it: "Non hai ancora prodotti nel tuo inventario" },
