export const LOCALES: Record<Idioma, string> = {
  es: "es-MX",
  en: "en-US",
  pt: "pt-BR",
  fr: "fr-FR",
  de: "de-DE",
  zh: "zh-CN",
  it: "it-IT",
};

export function traducir(
  clave: string,
  idioma: Idioma
): string {
  const entrada = TRADUCCIONES[clave];
  if (!entrada) return clave;
  return entrada[idioma] ?? entrada.es;
}
